                  />
                  <HexDisplay
                    label="Secret Key"
                    value="[hidden]"
                  />
                </div>
              )}
            </div>

            {/* Step 2: Sign & Verify */}
            <div className="rounded-xl border border-falcon-muted/20 bg-falcon-surface p-6">
