/**
 * Theme CSS custom properties — contract tests for globals.css
 *
 * Strategy: Parse globals.css directly to verify CSS custom properties match
 * the design spec. The CSS file is the single source of truth for all theme
 * tokens. No TypeScript constants are needed.
 *
 * Coverage:
 *   - Brand tokens (5) in @theme: primary, secondary, accent, success, error
 *   - Dark theme tokens (4) in .dark: bg, surface, text, muted
 *   - Light theme tokens (4) in .light: bg, surface, text, muted
 *   - Cross-theme invariant: dark-bg hex == light-text hex (inverted palette)
 */

import { describe, test, expect } from "bun:test"
import { readFileSync } from "fs"
import { join } from "path"

// ─── helpers ─────────────────────────────────────────────────────────────────

const CSS_PATH = join(import.meta.dir, "../../app/globals.css")
const CSS_CONTENT = readFileSync(CSS_PATH, "utf-8")

/**
 * Parse CSS custom properties from a delimited block of CSS text.
 * Returns a record of `--property-name` → `value`.
 */
function parseCustomProps(block: string): Record<string, string> {
  const result: Record<string, string> = {}
  const re = /--([\w-]+)\s*:\s*([^;}\n]+)/g
  let m: RegExpExecArray | null
  while ((m = re.exec(block)) !== null) {
