/**
 * Theme CSS custom properties — contract tests for globals.css
 *
 * Strategy: Parse globals.css directly to verify CSS custom properties match
 * the design spec. The CSS file is the single source of truth for all theme
 * tokens. No TypeScript constants are needed.
 *
 * CSS architecture (Tailwind v4 pattern):
 *   - @theme: defines --color-falcon-* tokens used by Tailwind utilities.
 *             Brand colors have static hex values.
 *             Theme-variant colors reference --falcon-* via var().
 *   - .dark:  sets --falcon-* base variables with dark palette values.
 *   - .light: sets --falcon-* base variables with light palette values.
 *
 * Coverage:
 *   - Brand tokens (5) in @theme: primary, secondary, accent, success, error
 *   - Dark theme base tokens (4) in .dark: bg, surface, text, muted
 *   - Light theme base tokens (4) in .light: bg, surface, text, muted
 *   - @theme wires --color-falcon-* to var(--falcon-*) for theme-variant tokens
 *   - Cross-theme invariant: dark-bg hex == light-text hex (inverted palette)
 */

import { describe, test, expect } from "bun:test"
import { readFileSync } from "fs"
import { join } from "path"

// ─── helpers ─────────────────────────────────────────────────────────────────

const CSS_PATH = join(import.meta.dir, "../../app/globals.css")
const CSS_CONTENT = readFileSync(CSS_PATH, "utf-8")

/**
 * Parse CSS custom properties from a delimited block of CSS text.
 * Returns a record of `--property-name` → `value`.
 */
function parseCustomProps(block: string): Record<string, string> {
  const result: Record<string, string> = {}
  const re = /--([\w-]+)\s*:\s*([^;}\n]+)/g
  let m: RegExpExecArray | null
  while ((m = re.exec(block)) !== null) {
    result[`--${m[1].trim()}`] = m[2].trim()
  }
  return result
}

/** Extract the first CSS block matching `selector { ... }` */
function extractBlock(css: string, selector: string): string {
  const escaped = selector.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")
  const match = css.match(new RegExp(`${escaped}\\s*\\{([^}]+)\\}`, "s"))
  return match ? match[1] : ""
}

/** Extract the @theme block */
function extractThemeBlock(css: string): string {
  const match = css.match(/@theme\s*\{([^}]+)\}/s)
  return match ? match[1] : ""
}

const themeBlock = extractThemeBlock(CSS_CONTENT)
const darkBlock = extractBlock(CSS_CONTENT, ".dark")
const lightBlock = extractBlock(CSS_CONTENT, ".light")

const themeVars = parseCustomProps(themeBlock)
const darkVars = parseCustomProps(darkBlock)
const lightVars = parseCustomProps(lightBlock)

// ─── Brand tokens (@theme) ────────────────────────────────────────────────

describe("Brand tokens in @theme — 5 shared colors with static hex values", () => {
  test("--color-falcon-primary is #6366f1 (indigo-500)", () => {
    expect(themeVars["--color-falcon-primary"]).toBe("#6366f1")
  })

  test("--color-falcon-secondary is #8b5cf6 (violet-500)", () => {
    expect(themeVars["--color-falcon-secondary"]).toBe("#8b5cf6")
  })

  test("--color-falcon-accent is #06b6d4 (cyan-500)", () => {
    expect(themeVars["--color-falcon-accent"]).toBe("#06b6d4")
  })

  test("--color-falcon-success is #10b981 (emerald-500)", () => {
    expect(themeVars["--color-falcon-success"]).toBe("#10b981")
  })

  test("--color-falcon-error is #ef4444 (red-500)", () => {
    expect(themeVars["--color-falcon-error"]).toBe("#ef4444")
  })
})

// ─── @theme var() wiring ─────────────────────────────────────────────────

describe("@theme var() wiring — theme-variant tokens reference --falcon-* base vars", () => {
  test("--color-falcon-bg references var(--falcon-bg)", () => {
    expect(themeVars["--color-falcon-bg"]).toBe("var(--falcon-bg)")
  })

  test("--color-falcon-surface references var(--falcon-surface)", () => {
    expect(themeVars["--color-falcon-surface"]).toBe("var(--falcon-surface)")
  })

  test("--color-falcon-text references var(--falcon-text)", () => {
    expect(themeVars["--color-falcon-text"]).toBe("var(--falcon-text)")
  })

  test("--color-falcon-muted references var(--falcon-muted)", () => {
    expect(themeVars["--color-falcon-muted"]).toBe("var(--falcon-muted)")
  })
})

// ─── Dark theme base tokens (.dark) ──────────────────────────────────────

describe(".dark CSS custom properties — 4 base variables for dark palette", () => {
  test(".dark block defines exactly 4 falcon base properties", () => {
    const falconProps = Object.keys(darkVars).filter((k) =>
      k.startsWith("--falcon-"),
    )
    expect(falconProps).toHaveLength(4)
  })

  test(".dark --falcon-bg is #0f172a (slate-900)", () => {
    expect(darkVars["--falcon-bg"]).toBe("#0f172a")
  })

  test(".dark --falcon-surface is #1e293b (slate-800)", () => {
    expect(darkVars["--falcon-surface"]).toBe("#1e293b")
  })

  test(".dark --falcon-text is #f8fafc (slate-50)", () => {
    expect(darkVars["--falcon-text"]).toBe("#f8fafc")
  })

  test(".dark --falcon-muted is #94a3b8 (slate-400)", () => {
    expect(darkVars["--falcon-muted"]).toBe("#94a3b8")
  })
})

// ─── Light theme base tokens (.light) ────────────────────────────────────

describe(".light CSS custom properties — 4 base variables for light palette", () => {
  test(".light block defines exactly 4 falcon base properties", () => {
    const falconProps = Object.keys(lightVars).filter((k) =>
      k.startsWith("--falcon-"),
    )
    expect(falconProps).toHaveLength(4)
  })

  test(".light --falcon-bg is #ffffff (white)", () => {
    expect(lightVars["--falcon-bg"]).toBe("#ffffff")
  })

  test(".light --falcon-surface is #f1f5f9 (slate-100)", () => {
    expect(lightVars["--falcon-surface"]).toBe("#f1f5f9")
  })

  test(".light --falcon-text is #0f172a (slate-900)", () => {
    expect(lightVars["--falcon-text"]).toBe("#0f172a")
  })

  test(".light --falcon-muted is #64748b (slate-500)", () => {
    expect(lightVars["--falcon-muted"]).toBe("#64748b")
  })
})

// ─── Cross-theme invariants ───────────────────────────────────────────────

describe("Cross-theme invariants — palette design contract", () => {
  test("dark and light blocks define the same 4 base property names", () => {
    const darkKeys = Object.keys(darkVars)
      .filter((k) => k.startsWith("--falcon-"))
      .sort()
    const lightKeys = Object.keys(lightVars)
      .filter((k) => k.startsWith("--falcon-"))
      .sort()
    expect(darkKeys).toEqual(lightKeys)
  })

  test("dark and light use different values for --falcon-bg", () => {
    expect(darkVars["--falcon-bg"]).not.toBe(lightVars["--falcon-bg"])
  })

  test("dark and light use different values for --falcon-text", () => {
    expect(darkVars["--falcon-text"]).not.toBe(lightVars["--falcon-text"])
  })

  test("inverted palette: dark --falcon-bg hex matches light --falcon-text hex", () => {
    // Design intent: dark bg (#0f172a) == light text (#0f172a) — fully inverted
    expect(darkVars["--falcon-bg"]).toBe(lightVars["--falcon-text"])
  })

  test("inverted palette: dark --falcon-text (#f8fafc) != light --falcon-bg (#ffffff)", () => {
    // Dark text (near-white #f8fafc) is different from light bg (pure white)
    expect(darkVars["--falcon-text"]).not.toBe(lightVars["--falcon-bg"])
  })
})

